import React, { useState, useEffect, useMemo } from "react";
import "./ReferralTable.css";

const API_URL =
  "https://nxtwave-assessments-backend-nxtwave-media-static.s3-ap-south-1.amazonaws.com/topin_beta/media/content_loading/uploads/d4457a9c-6134-46a5-b31c-60ad13a3e2f6_userData.json";

const ROWS_PER_PAGE = 10;

function SearchIcon() {
  return (
    <svg width="15" height="15" fill="none" viewBox="0 0 24 24">
      <circle cx="11" cy="11" r="7" stroke="currentColor" strokeWidth="2" />
      <path d="M16.5 16.5L21 21" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
    </svg>
  );
}

function ChevronIcon({ dir }) {
  return (
    <svg width="16" height="16" fill="none" viewBox="0 0 24 24" style={{ transform: dir === "left" ? "rotate(0deg)" : "rotate(180deg)" }}>
      <polyline points="15,18 9,12 15,6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function normalizeRow(row) {
  return {
    id: row.user_id,
    name: `User #${row.user_id}`,
    serviceName: row.service_name || "—",
    date: row.date || "—",
    profit: row.profit ? `₹${Number(row.profit).toLocaleString("en-IN")}` : "—",
  };
}

export default function ReferralTable() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);
    fetch(API_URL, { signal: controller.signal })
      .then((r) => {
        if (!r.ok) throw new Error("Network response was not ok");
        return r.json();
      })
      .then((json) => {
        const arr = Array.isArray(json) ? json : json.data || json.users || json.results || [];
        setData(arr.map(normalizeRow));
        setLoading(false);
      })
      .catch((err) => {
        if (err.name !== "AbortError") {
          setLoading(false);
        }
      });
    return () => controller.abort();
  }, []);

  const filtered = useMemo(() => {
    if (!search.trim()) return data;
    const q = search.trim().toLowerCase();
    return data.filter((row) => row.name.toLowerCase().includes(q));
  }, [data, search]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / ROWS_PER_PAGE));
  const currentPage = Math.min(page, totalPages);
  const pageData = filtered.slice((currentPage - 1) * ROWS_PER_PAGE, currentPage * ROWS_PER_PAGE);

  const handleSearch = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  const getPageNumbers = () => {
    const pages = [];
    if (totalPages <= 7) {
      for (let i = 1; i <= totalPages; i++) pages.push(i);
    } else {
      pages.push(1);
      if (currentPage > 3) pages.push("...");
      for (let i = Math.max(2, currentPage - 1); i <= Math.min(totalPages - 1, currentPage + 1); i++) pages.push(i);
      if (currentPage < totalPages - 2) pages.push("...");
      pages.push(totalPages);
    }
    return pages;
  };

  const avatarColors = ["#4f46e5","#7c3aed","#06b6d4","#10b981","#f59e0b","#ec4899","#ef4444","#0ea5e9"];
  const getColor = (id) => avatarColors[id % avatarColors.length];

  return (
    <section className="table-section">
      <div className="table-header">
        <div>
          <h2 className="section-title" style={{ marginBottom: 2 }}>Referral Transactions</h2>
          <p className="table-sub">
            {loading ? "Loading..." : `${filtered.length} record${filtered.length !== 1 ? "s" : ""} found`}
          </p>
        </div>
        <div className="table-search">
          <span className="table-search-icon"><SearchIcon /></span>
          <input
            type="text"
            placeholder="Search by name..."
            value={search}
            onChange={handleSearch}
            className="table-search-input"
          />
          {search && (
            <button className="clear-btn" onClick={() => { setSearch(""); setPage(1); }}>×</button>
          )}
        </div>
      </div>

      <div className="table-wrap">
        {loading ? (
          <div className="table-state">
            <div className="spinner" />
            <p>Loading referral data...</p>
          </div>
        ) : (
          <table className="ref-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Name</th>
                <th>Service Name</th>
                <th>Date</th>
                <th>Profit</th>
              </tr>
            </thead>
            <tbody>
              {pageData.length === 0 ? (
                <tr>
                  <td colSpan={5}>
                    <div className="no-data">
                      <svg width="48" height="48" fill="none" viewBox="0 0 24 24" style={{ opacity: 0.3 }}>
                        <circle cx="11" cy="11" r="8" stroke="currentColor" strokeWidth="1.5"/>
                        <path d="m21 21-4.35-4.35" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
                      </svg>
                      <p>No matching data</p>
                      <span>Try a different name to search again</span>
                    </div>
                  </td>
                </tr>
              ) : (
                pageData.map((row, idx) => (
                  <tr key={row.id}>
                    <td className="row-num">{(currentPage - 1) * ROWS_PER_PAGE + idx + 1}</td>
                    <td>
                      <div className="name-cell">
                        <span className="row-avatar" style={{ background: getColor(row.id) }}>
                          U{row.id}
                        </span>
                        <span className="row-name">{row.name}</span>
                      </div>
                    </td>
                    <td>
                      <span className="service-chip">{row.serviceName}</span>
                    </td>
                    <td className="date-cell">{row.date}</td>
                    <td>
                      <span className="profit-value">{row.profit}</span>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        )}
      </div>

      {!loading && filtered.length > 0 && (
        <div className="pagination">
          <span className="page-info">
            Page {currentPage} of {totalPages} · {filtered.length} records
          </span>
          <div className="page-controls">
            <button
              className="page-btn nav-btn"
              disabled={currentPage === 1}
              onClick={() => setPage(currentPage - 1)}
            >
              <ChevronIcon dir="left" />
            </button>

            {getPageNumbers().map((p, i) =>
              p === "..." ? (
                <span key={`e${i}`} className="ellipsis">…</span>
              ) : (
                <button
                  key={p}
                  className={`page-btn${currentPage === p ? " active" : ""}`}
                  onClick={() => setPage(p)}
                >
                  {p}
                </button>
              )
            )}

            <button
              className="page-btn nav-btn"
              disabled={currentPage === totalPages}
              onClick={() => setPage(currentPage + 1)}
            >
              <ChevronIcon dir="right" />
            </button>
          </div>
        </div>
      )}
    </section>
  );
}
